      function CF_00420Formula return Date is
 v_calc_begin_date_varchar VARCHAR2(10);
 V_DATE DATE;

	CURSOR Cur_is_new_assignee IS
	SELECT 1
	FROM PEN_DECISION_INSTANCE_DEATH A
	WHERE A.ACC_ACCOUNT_NO = :P_Acc_Account_No
	AND STATUS = '1'
	AND A.NEW_OLD_DEC IN ('NEW-INS','NEW');
	
	v_is_new_assignee_flg NUMBER:=0;
	
	CURSOR Cur_death_start_date IS
	SELECT A.start_date
	FROM PEN_ACCOUNT A
	WHERE A.ACCOUNT_NO = :P_Acc_Account_No_Dir;	
	
BEGIN
		   OPEN Cur_is_new_assignee;
  	   FETCH Cur_is_new_assignee
  	   INTO v_is_new_assignee_flg;
  	   CLOSE Cur_is_new_assignee;

  v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1',
			 0,0,'00001','00318','00420');
			  
		IF v_is_new_assignee_flg = 1 THEN
					OPEN Cur_death_start_date;
				  FETCH Cur_death_start_date
				  INTO V_DATE;
				  CLOSE Cur_death_start_date;
		ELSE
			  V_DATE:= TO_DATE(v_calc_begin_date_varchar,'DD/MM/RRRR'); 
		END IF;
  
  IF v_calc_begin_date_varchar IS NOT NULL OR v_is_new_assignee_flg = 1 THEN 
    RETURN (V_DATE); 
  ELSE 
   RETURN '';
  END IF;
END;

      FUNCTION CF_PAYMENT_AMOUNTFormula RETURN NUMBER IS

v_calc_begin_date_varchar VARCHAR2(10);
v_calc_begin_date DATE;
V_AMOUNT NUMBER;

	CURSOR Cur_is_new_assignee IS
	SELECT 1
	FROM PEN_DECISION_INSTANCE_DEATH A
	WHERE A.ACC_ACCOUNT_NO = :P_Acc_Account_No
	AND STATUS = '1'
	AND A.NEW_OLD_DEC IN ('NEW-INS','NEW');
	
	v_is_new_assignee_flg NUMBER:=0;
	
	CURSOR Cur_death_start_date IS
	SELECT A.start_date
	FROM PEN_ACCOUNT A
	WHERE A.ACCOUNT_NO = :P_Acc_Account_No_Dir;	
	
BEGIN
		   OPEN Cur_is_new_assignee;
  	   FETCH Cur_is_new_assignee
  	   INTO v_is_new_assignee_flg;
  	   CLOSE Cur_is_new_assignee;
  	   
	  v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1',
					 0,:p_group_id,'00001','00318','00420');
					 
		IF v_calc_begin_date_varchar IS NOT NULL THEN
		   v_calc_begin_date := TO_DATE(v_calc_begin_date_varchar,'DD/MM/RRRR');
		END IF;

		IF v_is_new_assignee_flg = 1 THEN
					OPEN Cur_death_start_date;
				  FETCH Cur_death_start_date
				  INTO v_calc_begin_date;
				  CLOSE Cur_death_start_date;
		END IF;

	V_AMOUNT := Penbat_Payments.Calc_Total_Scale_Raise_Back (NULL
																													 ,NULL
																													 ,v_calc_begin_date
																												 	 ,:P_ACC_START_DATE
																													 ,:P_PENSION_AMOUNT);
  
  RETURN (ROUND(V_AMOUNT,2)+:P_PENSION_AMOUNT); 
  
  
END;

