		AND A.DT_DECISION_YEAR=:P_DT_DECISION_YEAR_DIR
		AND A.DT_DOCUMENT_TYPE_DEC_CODE='1';
 END IF;

IF :CF_AWARD_FLG='0' THEN 

	 IF :PROTOCOL_NO IS NOT NULL THEN 
	     V_STRING := 'αρμόδιος να κρίνει τη με αριθμό Πρωτοκόλλου '|| :PEN_APPLICATION_INSTANCES_PROT || ' αίτηση ' ||:CS_3 ||' με τα κάτωθι στοιχεία:';
	 ELSE 
	     V_STRING := 'αρμόδιος να κρίνει οίκοθεν την περίπτωση ' ||:CS_3 || ' με τα κάτωθι στοιχεία:';
	 END IF;    
ELSE
   IF V_PROTOCOL_NO IS NOT NULL THEN 
	     V_STRING := 'αρμόδιος να κρίνει τη με αριθμό Πρωτοκόλλου '|| V_PROTOCOL_NO || '-' || V_PROTOCOL_DATE ||' αίτηση ' ||:CS_3 ||' με τα κάτωθι στοιχεία:';
	 ELSE 
	     V_STRING := 'αρμόδιος να κρίνει οίκοθεν την περίπτωση ' || :CS_3 || ' με τα κάτωθι στοιχεία:';
	 END IF;    

END IF;

  return (V_STRING);
end;

