	        ELSE
	        	RETURN ' ';
			    END IF;
		  END IF;
	ELSE
 		  	OPEN cur_SF00508;
		  	FETCH cur_SF00508
		  	INTO SF508_VALUE;
		  	CLOSE cur_SF00508;

       IF SF508_VALUE IS NOT NULL THEN  		  	
		  	RETURN TO_CHAR(SF508_VALUE) || '%';
       ELSE
       	RETURN ' ';
       END IF;	
  END IF;
END;

