      function CF_TERMINATION_TRI_YEARSForm return Date is

V_RESULT DATE;

CURSOR cur_DATE IS 
 SELECT A.VALUE
 FROM
       PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
  WHERE
     A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
     A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = :P_Acc_Account_No_DIR AND
       A.Title_Code         = '00315' AND
	     A.Dec_Fact_Type_Code = '00059';

begin

  IF :DATE_OF_DEATH IS NOT NULL THEN 
  	RETURN LAST_DAY(ADD_MONTHS(:DATE_OF_DEATH,36))+1;
  ELSE
		  OPEN cur_DATE;
		  FETCH cur_DATE
		  INTO V_RESULT;
		  CLOSE cur_DATE;

      RETURN LAST_DAY(ADD_MONTHS(V_RESULT,36))+1;  

  END IF;
  
END;

      FUNCTION CF_INSURED_IND_PLUS65Formula RETURN DATE IS
   V_BIRTH_DATE DATE;
BEGIN
  /*FIND INDIRECT MEMBER DATE OF DEATH +  65 YEARS*/
  SELECT DATE_OF_BIRTH
  INTO V_BIRTH_DATE
  FROM REG_INSURED A
  WHERE A.INSURED_ID = :P_INSURED_ID_IND;
 
  RETURN ADD_MONTHS(V_BIRTH_DATE,65*12);
 
END;

      FUNCTION CF_COMPARE_DATESFormula RETURN CHAR IS
 
 V_CHAR VARCHAR2(10);
 
BEGIN
  IF :CF_INSURED_IND_PLUS65  <= :CF_TERMINATION_TRI_YEARS THEN 
      V_CHAR := '30%';
  ELSIF :CF_INSURED_IND_PLUS65  > :CF_TERMINATION_TRI_YEARS THEN
  	  V_CHAR := '50%';
  END IF;
  
  RETURN V_CHAR;
END;

