      function CF_13Formula return Char is
cursor cur_pen_account_rep is
select 
account_no, 
total_days, 
total_days_h, 
flg_kind, 
pen_class,
amnt1,
amnt2,
amnt1+amnt2 tot_amnt,
perc,
amnt3,
LOWEST_CALC_DAYS,
LOWEST_ASS_TOTAL_PRCN,
LOWEST_AMOUNT,
LOWEST_INCR,
LOWEST_REDUCTION
from pen_account_rep
where account_no=:P_ACC_ACCOUNT_NO_DIR;

v_cur_pen_account_rep  cur_pen_account_rep%rowtype;

my_total_days1  number;
my_total_days2  number;
my_total_days_h number;
my_text1				varchar2(512);
my_text2				varchar2(512);
my_text3				varchar2(512);
my_text4				varchar2(512);

begin
	
open 	cur_pen_account_rep;
fetch cur_pen_account_rep
into  v_cur_pen_account_rep;
close cur_pen_account_rep;

if v_cur_pen_account_rep.total_days<300 then                       
my_total_days1	:=(v_cur_pen_account_rep.total_days/300)*300;
else
my_total_days1	:=floor(v_cur_pen_account_rep.total_days/300)*300;
end if;	
my_total_days2	:=floor((v_cur_pen_account_rep.total_days-10500)/300)*300;
my_total_days_h	:=floor(v_cur_pen_account_rep.total_days_h/300)*300;


IF :CF_PRODUCT_CODE = '00003' THEN

	if v_cur_pen_account_rep.flg_kind='1' then
		 	my_text1:='ΤO ΒΑΣΙΚΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||round(v_cur_pen_account_rep.pen_class,2)||' *  20% * ( '||my_total_days1||'/10500 '||' ) '||' = '||Ltrim(to_char(round(v_cur_pen_account_rep.amnt1,2),'999G999G990D90'));
	elsif v_cur_pen_account_rep.flg_kind='2' then
			my_text1:='ΤO ΒΑΣΙΚΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||'0.02 * '||'10500/300* '||round(v_cur_pen_account_rep.pen_class,2)||' + '||'0.03* '||my_total_days2||'/300 '||'*'||round(v_cur_pen_account_rep.pen_class,2)||'='||Ltrim(to_char(round(v_cur_pen_account_rep.amnt1,2),'999G999G990D90'));
	else
			my_text1:='ΤO ΒΑΣΙΚΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||round(v_cur_pen_account_rep.pen_class,2)||' *  20% * ( '||my_total_days1||'/10500 '||' ) '||' = '||Ltrim(to_char(round(v_cur_pen_account_rep.amnt1,2),'999G999G990D90'));
	end if;
	
	if v_cur_pen_account_rep.total_days_h<>0 then
		 my_text2:='TΟ ΠΟΣΟ ΤΗΣ ΠΡΟΣΑΥΞΗΣΗΣ ΒΑΡΕΩΝ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ : '||'0.02 * 1.2 * '||my_total_days_h||'/300 '||' * '||round(v_cur_pen_account_rep.pen_class,2)||'='||Ltrim(to_char(round(v_cur_pen_account_rep.amnt2,2),'999G999G990D90'));
		 my_text1:=my_text1||chr(10)||my_text2;
	end if;	 
		 
	if nvl(round(v_cur_pen_account_rep.amnt3,2),0) != nvl(round(v_cur_pen_account_rep.amnt1,2),0) + nvl(round(v_cur_pen_account_rep.amnt2,2),0) then
			my_text3:='ΤΟ ΟΠΟΙΟ ΜΕ ΤΗΝ EΤΗΣΙΑ ΑΥΞΗΣΗ '||v_cur_pen_account_rep.perc*100||'ΔΙΑΜΟΡΦΩΝΕΤΑΙ ΣΕ: '||Ltrim(to_char(round(v_cur_pen_account_rep.amnt3,2),'999G999G990D90'));
			my_text1:=my_text1||chr(10)||my_text3;
	else
			my_text3:='ΣΤΟ ΟΠΟΙΟ ΔΕΝ ΕΧΕΙ ΔΟΘΕΙ EΤΗΣΙΑ ΑΥΞΗΣΗ ';
			my_text1:=my_text1||chr(10)||my_text3;
	end if;

	
	IF v_cur_pen_account_rep.LOWEST_CALC_DAYS IS NOT NULL THEN
		IF v_cur_pen_account_rep.LOWEST_REDUCTION IS NOT NULL THEN
		 my_text4:='ΤO ΚΑΤΩΤΑΤΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||'80% * [ '||round(v_cur_pen_account_rep.pen_class,2)||' *  20% * ( '||v_cur_pen_account_rep.LOWEST_CALC_DAYS||'/10500 '||' ) + αυξήσεις('||v_cur_pen_account_rep.LOWEST_INCR||')] * ('||v_cur_pen_account_rep.LOWEST_REDUCTION||') * ('||:p_percentage||'/'||v_cur_pen_account_rep.LOWEST_ASS_TOTAL_PRCN||') = '||ROUND(v_cur_pen_account_rep.LOWEST_AMOUNT*:p_percentage/v_cur_pen_account_rep.LOWEST_ASS_TOTAL_PRCN,2);
    ELSE
		 my_text4:='ΤO ΚΑΤΩΤΑΤΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||'80% * [ '||round(v_cur_pen_account_rep.pen_class,2)||' *  20% * ( '||v_cur_pen_account_rep.LOWEST_CALC_DAYS||'/10500 '||' ) + αυξήσεις('||v_cur_pen_account_rep.LOWEST_INCR||')] * ('||:p_percentage||'/'||v_cur_pen_account_rep.LOWEST_ASS_TOTAL_PRCN||') = '||ROUND(v_cur_pen_account_rep.LOWEST_AMOUNT*:p_percentage/v_cur_pen_account_rep.LOWEST_ASS_TOTAL_PRCN,2);
		END IF;
		 my_text1:=my_text1||chr(10)||my_text4;
	END IF;	
	

ELSE
	
	IF v_cur_pen_account_rep.LOWEST_CALC_DAYS IS NOT NULL THEN
		IF v_cur_pen_account_rep.LOWEST_REDUCTION IS NOT NULL THEN
		 my_text1:='ΤO ΚΑΤΩΤΑΤΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||'80% * [ '||round(v_cur_pen_account_rep.pen_class,2)||' *  20% * ( '||v_cur_pen_account_rep.LOWEST_CALC_DAYS||'/10500 '||' ) + αυξήσεις('||v_cur_pen_account_rep.LOWEST_INCR||')] * ('||v_cur_pen_account_rep.LOWEST_REDUCTION||') * ('||:p_percentage||'/'||v_cur_pen_account_rep.LOWEST_ASS_TOTAL_PRCN||') = '||ROUND(v_cur_pen_account_rep.LOWEST_AMOUNT*:p_percentage/v_cur_pen_account_rep.LOWEST_ASS_TOTAL_PRCN,2);
    ELSE
		 my_text1:='ΤO ΚΑΤΩΤΑΤΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||'80% * [ '||round(v_cur_pen_account_rep.pen_class,2)||' *  20% * ( '||v_cur_pen_account_rep.LOWEST_CALC_DAYS||'/10500 '||' ) + αυξήσεις('||v_cur_pen_account_rep.LOWEST_INCR||')] * ('||:p_percentage||'/'||v_cur_pen_account_rep.LOWEST_ASS_TOTAL_PRCN||') = '||ROUND(v_cur_pen_account_rep.LOWEST_AMOUNT*:p_percentage/v_cur_pen_account_rep.LOWEST_ASS_TOTAL_PRCN,2);
		END IF;
	END IF;	
	
END IF;
		
return my_text1;
	
	
  
end;

      function CF_13FORMULA0013 return Char is

V_PROMPT     VARCHAR2(500);

Cursor cur_award_prompt Is
 SELECT A.EXTRA_ANNOUNCE_PAY_BRANCH
FROM PEN_DECISION_INSTANCE A										 
WHERE A.DOCUMENT_TYPE_DEC_CODE_SR ='1'  AND 
	A.DECISION_YEAR_SR=  :P_DT_DECISION_YEAR_SR AND 
	A.DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR AND 
	A.INCR_SEQ_NO_SR =   :P_DT_INCR_SEC_NO_SR;

begin
 
 OPEN cur_award_prompt;
   FETCH cur_award_prompt 
   INTO V_PROMPT;
 CLOSE cur_award_prompt;
 
 
 RETURN V_PROMPT;
 
end;

