      function CF_13FORMULA0008 return Char is
V_DISPLAY VARCHAR2(100);
V_DATE DATE;

begin
	
 	v_DATE := Find_Fact_Sub_Death_Varchar(:P_Insured_Id_IND,:P_DT_DECISION_YEAR_SR,:P_DT_DEC_UNIT_CODE_SR,:P_DT_INCR_SEC_NO_SR, '1',
			 0,0,'00001','00315','00059'); ---HM/NIA FILAKISHS
	
	
IF :PRODUCT_CODE='00003' THEN
	IF :SEX='Α' THEN
	  V_DISPLAY:='του ασφαλισμένου στο';
  end if;
  IF :SEX='Θ' THEN
	  V_DISPLAY:='της ασφαλισμένης στο';
  end if;
END IF;

IF :PRODUCT_CODE='00004' THEN
	IF :SEX='Α' THEN
		IF :DATE_OF_DEATH IS NOT NULL THEN 
	    V_DISPLAY:='του συνταξιούχου στο';
		ELSIF V_DATE IS NOT NULL THEN 
			V_DISPLAY:='του συνταξιούχου στο';
    END IF;
  END IF;
  IF :SEX='Θ' THEN
	  IF :DATE_OF_DEATH IS NOT NULL THEN 
	    V_DISPLAY:='της συνταξιούχου στο';
	  ELSIF V_DATE IS NOT NULL THEN 
	  	V_DISPLAY:='της συνταξιούχου στο';
    END IF;
  end if;
END IF;


return v_display;
end;

