      function CF_soixeia_paymentsFormula return Char is

to_return varchar2(500);
v_iban      varchar2(60);

cursor Cur_Fact_Subtype_Existance IS 
  select distinct pen_dec_fact_types_instance.value
  from  pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code='00069' AND 
pen_dec_fact_types_instance.ins_insured_id=  :P_INSURED_ID_IND AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DT_INCR_SEC_NO_SR  AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR  AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :P_DT_DEC_UNIT_CODE_SR AND
pen_dec_fact_types_instance.dec_fact_type_code = '00111';
  
cursor Cur_Fact_Subtype_Existance_2 IS 
  select distinct pen_dec_fact_types_instance.value
  from  pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code='00069' AND 
pen_dec_fact_types_instance.ins_insured_id=  :P_INSURED_ID_IND AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DT_INCR_SEC_NO_SR  AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR  AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :P_DT_DEC_UNIT_CODE_SR AND
pen_dec_fact_types_instance.dec_fact_type_code = '00584';

V_DEATH_REASON VARCHAR2(20);
begin
    to_return :='';
    v_iban:=null;
       open Cur_Fact_Subtype_Existance;
     fetch Cur_Fact_Subtype_Existance into v_iban;
     close Cur_Fact_Subtype_Existance; 
     open Cur_Fact_Subtype_Existance_2;
     fetch Cur_Fact_Subtype_Existance_2 into V_DEATH_REASON;
     close Cur_Fact_Subtype_Existance_2;                                              
    if v_iban is not null then
        IF V_DEATH_REASON='1' THEN
            to_Return:='Πληρωμή Σύνταξης χωρίς πίστωση σε Τραπεζικό Λογαριασμό.';
        ELSE    
         to_Return:='Πληρωμή Σύνταξης με πίστωση σε Τραπεζικό Λογαριασμό.';
        END IF; 
    end if;
   return to_Return;

end;

      function CF_DEBT_DESCRFormula return Char is
TO_RETURN VARCHAR2(1000);

CURSOR C1 IS
 SELECT PRCN_DESCR
   FROM PPI_PEN_DEBTS_PRCN
  WHERE PRCN= :DEDUCTION_PENSION_FACTOR;
  
v_temp_cnt number          ;
  
V_PRCN_DESCR VARCHAR2(200);  
begin
  if :debt_id='31' then
  	to_return:=:num_debt||'. '||'Συμψηφίζεται '||:descr||' Συνολικού Ποσού: '||:TOTAL_DEDUCTION_AMMOUNT ||' ΕΥΡΩ';
  else
  	OPEN C1;
  	FETCH C1 INTO V_PRCN_DESCR;
  	CLOSE C1;
  	to_return:='Παρακράτηση ';
  	if :DOSAGE_AMOUNT is not null then 
  			to_return:=:num_debt||'. '||to_return||' ποσού '||:DOSAGE_AMOUNT||' ΕΥΡΩ της μηνιαίας Σύνταξης ';
  	else
  			to_return:=:num_debt||'. '||to_return||' ποσοστού '||V_PRCN_DESCR||' της μηνιαίας Σύνταξης ';
  	end if;		
  		to_return:=to_return||' για '||:descr||' από Συνολικό Ποσό: '||:TOTAL_DEDUCTION_AMMOUNT ||' ΕΥΡΩ';
  end if;	
  return TO_RETURN;
end;

